                    'price'    => $v['price'],
                    'contact'  => $v['contact'],
                    'address'  => $v['address'],
                    'notes'    => 'Vendor ' . $category . ' profesional',
                    'rating'   => $v['rating'],
                ]);
            }
        }
    }
}
